// No parameters — empty parens required
const greet = () => 'Hello!';

// One parameter — parens optional (common to omit)
const double = (x: number) => x * 2;
const doubleAlt = x => x * 2;   // parens omitted (valid JS, TypeScript usually infers)

// Multiple parameters — parens required
const add = (a: number, b: number) => a + b;

// Block body — requires explicit return
const clamp = (n: number, min: number, max: number) => {
  if (n < min) return min;
  if (n > max) return max;
  return n;
};

// Without parens — syntax error (brace = block body start)
// const makeUser = (name: string) => { name, id: 1 };  // wrong

// With parens — brace is the object literal
const makeUser = (name: string) => ({ name, id: Date.now() });
makeUser('Deiva');  // { name: 'Deiva', id: 1751234567890 }

const fetchUser = async (id: number): Promise<User> => {
  const res = await fetch(`/api/users/${id}`);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

class Poller {
  count = 0;

  // ✗ Regular function — this is lost inside the callback
  startBroken() {
    setInterval(function () {
      this.count++;               // TypeError: Cannot set property 'count' of undefined
    }, 1000);
  }

  // ✓ Arrow function — this captured from startWorking()'s scope (Poller instance)
  startWorking() {
    setInterval(() => {
      this.count++;               // this = Poller instance
      console.log(this.count);
    }, 1000);
  }
}

const arrow = () => this;

// call/apply/bind are silently ignored for arrow functions
arrow.call({ x: 1 });    // still the outer this, not { x: 1 }
arrow.bind({ x: 1 })();  // same — bind returns a new function, but this is still lexical

// This is intentional: predictability over flexibility

@Component({
  selector: 'app-counter',
  template: `
    <button (click)="increment()">+</button>
    <button (click)="decrement()">-</button>
    <p>{{ count }}</p>
  `,
})
export class CounterComponent {
  count = 0;

  // Regular method — safe in template (Angular calls via component instance)
  increment() { this.count++; }

  // Arrow class field — required when method is passed as a callback reference
  decrement = () => { this.count--; };

  // Also safe to pass as a reference to external APIs:
  // someExternalLib.on('event', this.decrement);  // always CounterComponent
}

