@Injectable({ providedIn: 'root' })
export class OrderService {
  private taxRate = 0.08;

  constructor(private http: HttpClient) {}

  getOrders(): Observable<Order[]> {
    return this.http.get<Order[]>('/api/orders').pipe(
      map(orders => orders.filter(o => o.active)),           // arrow in map
      map(orders => orders.map(o => ({                       // arrow in map returning object
        ...o,
        totalWithTax: o.total * (1 + this.taxRate),          // this = OrderService ✓
      }))),
      tap(orders => console.log(`Loaded ${orders.length} orders`)),
    );
  }
}

// ✗ Arrow as object method — this is the outer scope, not the object
const config = {
  timeout: 5000,
  getTimeout: () => this.timeout,   // 'this' is NOT config
};
config.getTimeout();   // undefined (or window.timeout)

// ✓ Shorthand method — this is correctly config
const config2 = {
  timeout: 5000,
  getTimeout() { return this.timeout; },
};
config2.getTimeout();  // 5000

interface Product {
  id: number;
  name: string;
  price: number;
  category: string;
  active: boolean;
}

const products: Product[] = [/* ... */];

// Find active electronics under $500, return names sorted alphabetically
const result = products
  .filter(p => p.active && p.category === 'electronics')
  .filter(p => p.price < 500)
  .map(p => p.name)
  .sort();

// Compute total revenue from active products
const revenue = products
  .filter(p => p.active)
  .reduce((sum, p) => sum + p.price, 0);

// Group by category using reduce + arrow
const byCategory = products.reduce<Record<string, Product[]>>((acc, p) => {
  (acc[p.category] ??= []).push(p);
  return acc;
}, {});

// compose: apply functions right-to-left
const compose = <T>(...fns: Array<(x: T) => T>) =>
  (x: T) => fns.reduceRight((v, fn) => fn(v), x);

// pipe: apply functions left-to-right (more natural reading order)
const pipe = <T>(...fns: Array<(x: T) => T>) =>
  (x: T) => fns.reduce((v, fn) => fn(v), x);

const process = pipe(
  (s: string) => s.trim(),
  (s: string) => s.toLowerCase(),
  (s: string) => s.replace(/\s+/g, '-'),
);

process('  Hello World  ');  // 'hello-world'

