// Curried HTTP factory (used in Angular guards / interceptors)
const withHeader =
  (key: string) =>
  (value: string) =>
  (req: HttpRequest<unknown>) =>
    req.clone({ setHeaders: { [key]: value } });

const withAuth = withHeader('Authorization');
const withBearer = withAuth(`Bearer ${token}`);
