@Injectable({ providedIn: 'root' })
export class ApiService {
  constructor(private http: HttpClient) {}

  // Factory: returns a partially applied GET function for a base path
  resource = (basePath: string) => ({
    getAll: <T>() => this.http.get<T[]>(basePath),
    getOne: <T>(id: number) => this.http.get<T>(`${basePath}/${id}`),
    create: <T>(body: unknown) => this.http.post<T>(basePath, body),
    update: <T>(id: number, body: unknown) => this.http.put<T>(`${basePath}/${id}`, body),
  });
}

// Usage
const users = apiService.resource('/api/users');
users.getAll<User>();
users.getOne<User>(42);

// Generic arrow function
const identity = <T>(x: T): T => x;

// In .tsx files — add trailing comma to disambiguate from JSX
const identity2 = <T,>(x: T): T => x;

// With a constraint
const firstItem = <T extends unknown[]>(arr: T): T[0] => arr[0];

// Generic factory arrow
const createPair = <A, B>(a: A, b: B): [A, B] => [a, b];
createPair('hello', 42);    // ['hello', 42]
createPair(true, { x: 1 }); // [true, { x: 1 }]

// counter.component.spec.ts
describe('CounterComponent', () => {
  let component: CounterComponent;
  let fixture: ComponentFixture<CounterComponent>;

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [CounterComponent],
    }).compileComponents();

    fixture = TestBed.createComponent(CounterComponent);
    component = fixture.componentInstance;
    fixture.detectChanges();
  });

  it('increments count', () => {
    component.increment();
    expect(component.count).toBe(1);
  });

  it('arrow field keeps context when detached', () => {
    // Detach method — regular method would lose 'this', arrow field doesn't
    const { decrement } = component;
    decrement();
    expect(component.count).toBe(-1);
  });

  it('renders updated count', () => {
    component.increment();
    fixture.detectChanges();
    const el = fixture.nativeElement.querySelector('p');
    expect(el.textContent).toContain('1');
  });
});

@Component({ ... })
export class DashboardComponent {
  // signal — initial value
  userId = signal<number | null>(null);
  items = signal<Item[]>([]);

  // computed — derived value, arrow callback
  itemCount = computed(() => this.items().length);
  hasItems = computed(() => this.items().length > 0);

  // computed with transformation
  sortedItems = computed(() =>
    [...this.items()].sort((a, b) => a.name.localeCompare(b.name))
  );

  // Arrow in update() — receives current value, returns new value
  addItem(item: Item) {
    this.items.update(current => [...current, item]);
  }

  removeItem(id: number) {
    this.items.update(current => current.filter(i => i.id !== id));
  }

  // effect — arrow callback runs whenever dependencies change
  constructor() {
    effect(() => {
      console.log('Item count changed:', this.itemCount());
    });
  }
}

// Functional route guard — arrow function as the guard itself
export const authGuard: CanActivateFn = (route, state) => {
  const authService = inject(AuthService);
  const router = inject(Router);

  if (authService.isLoggedIn()) {
    return true;
  }
  return router.createUrlTree(['/login'], {
    queryParams: { returnUrl: state.url },
  });
};

// In routes:
const routes: Routes = [
  { path: 'dashboard', component: DashboardComponent, canActivate: [authGuard] },
];
